# 如果 stock_codes 为空，则遍历 data 目录下所有 CSV 文件
if not stock_codes:
    stock_codes = [f.split(".")[0] for f in os.listdir(data_dir) if f.endswith(".csv")]

# 存储结果的数据框
results = []

for stock_code in stock_codes:
    if use_akshare:
        print(f"🔄 正在从 AkShare 获取 {stock_code} 的数据...")
        df = ak.stock_zh_a_hist(symbol=stock_code, period="daily", start_date="20240101", end_date="20250225", adjust="qfq")
        if df.empty:
            print(f"❌ 未能获取 {stock_code} 的数据，请检查代码是否正确！")
            continue
        df.rename(columns={"日期": "date", "收盘": "close"}, inplace=True)
    else:
        file_path = os.path.join(data_dir, f"{stock_code}.csv")
        if not os.path.exists(file_path):
            print(f"❌ 文件 {file_path} 不存在，请检查路径！")
            continue
        df = pd.read_csv(file_path)

    # 处理数据（确保列名正确）
    if "日期" in df.columns:
        df["日期"] = pd.to_datetime(df["日期"])
        df.set_index("日期", inplace=True)
    elif "date" in df.columns:
        df["date"] = pd.to_datetime(df["date"])
        df.set_index("date", inplace=True)
    else:
        print(f"❌ 数据 {stock_code} 中没有找到 '日期' 或 'date' 列，请检查数据格式！")
        continue

    # 提取收盘价
    if "收盘" in df.columns:
        df = df[["收盘"]]
    elif "close" in df.columns:
        df = df[["close"]]
    else:
        print(f"❌ 数据 {stock_code} 中没有找到 '收盘' 或 'close' 列，请检查数据格式！")
        continue

    # 计算日收益率
    df["收益率"] = df.iloc[:, 0].pct_change()
    df.dropna(inplace=True)

    # 计算均值和标准差
    mu = df["收益率"].mean()
    sigma = df["收益率"].std()
    S0 = df.iloc[-1, 0]

    # ✅ **优化点：使用 NumPy 向量化计算**
    np.random.seed(42)
    Z = np.random.standard_normal((num_simulations, num_days))  # 生成所有随机数
    price_paths = np.zeros((num_simulations, num_days))
    price_paths[:, 0] = S0

    for t in range(1, num_days):
        price_paths[:, t] = price_paths[:, t - 1] * np.exp((mu - 0.5 * sigma ** 2) * dt + sigma * np.sqrt(dt) * Z[:, t])

    # 计算价格范围（95% 置信区间）
    future_prices = price_paths[:, -1]
    price_mean = round(np.mean(future_prices), 3)
    price_5_percentile = round(np.percentile(future_prices, 5), 3)
    price_95_percentile = round(np.percentile(future_prices, 95), 3)

    # 获取昨日收盘价
    yesterday_price = df.iloc[-2, 0] if len(df) > 1 else None

    # 计算预测价格相对于昨日收盘价的涨幅
    increase_percent = round(((price_mean - yesterday_price) / yesterday_price) * 100, 2) if yesterday_price else None

    # 存储结果
    results.append([stock_code, price_mean, yesterday_price, increase_percent])

    # 输出预测结果
    print(f"{stock_code} 未来 {num_days} 天股价预测区间：")
    print(f" - 95% 置信区间: [{price_5_percentile}, {price_95_percentile}]")
    print(f" - 预测均值: {price_mean}")
    print(f" - 昨日收盘价: {yesterday_price}")
    print(f" - 昨日收盘价相对预测价格变化百分比: {increase_percent}%")

# 按照第四列（变化百分比）排序
results_df = pd.DataFrame(results, columns=["股票代码", "预测价格", "昨日收盘价", "预测比昨日收盘价变化%"])
results_df.sort_values(by="预测比昨日收盘价变化%", ascending=False, inplace=True)
results_df.to_csv("predicted_prices.csv", index=False, encoding='utf-8-sig')
print("✅ 预测结果已保存到 predicted_prices.csv，并按变化百分比排序")

# 提取前20个股票代码并保存到 txt 文件
top_20_stocks = results_df.head(20)["股票代码"].tolist()
with open("top_20_stocks.txt", "w", encoding="utf-8") as f:
    for stock in top_20_stocks:
        f.write(stock + "\n")

